{
  "plan": [
    {
      "tool": "jira.list_tickets",
      "arguments": {
        "project": "requirements",
        "status": ["Open", "In Progress", "Backlog"],
        "limit": 100
      },
      "depends_on": []
    },
    {
      "tool": "calendar.list_events",
      "arguments": {
        "time_min": "now",
        "time_max": "+7d",
        "calendar_type": "team"
      },
      "depends_on": []
    },
    {
      "tool": "iam.check_permission",
      "arguments": {
        "resource": "calendar.create_event",
        "action": "create"
      },
      "depends_on": []
    },
    {
      "tool": "calendar.create_event",
      "arguments": {
        "title": "Cross-Team Standup - Project Requirements Review",
        "description": "Daily standup to review project requirements and backlog items. Active tickets: $1.count",
        "start_time": "$2.next_available_slot",
        "duration_minutes": 30,
        "attendees": "$2.team_members"
      },
      "depends_on": [1, 2, 3]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "calendar_event_created",
        "resource_type": "calendar_event",
        "resource_id": "$4.event_id",
        "details": {
          "event_title": "Cross-Team Standup - Project Requirements Review",
          "scheduled_time": "$4.start_time",
          "attendees": "$4.attendees",
          "permission_verified": "$3.allowed"
        }
      },
      "depends_on": [4]
    },
    {
      "tool": "slack.post_message",
      "arguments": {
        "channel": "#cross-team-collaboration",
        "message": "📅 **Cross-Team Standup Scheduled**\n\n**Meeting Details:**\n• Event ID: $4.event_id\n• Time: $4.start_time\n• Duration: 30 minutes\n• Attendees: $4.attendees\n\n**Agenda:**\n1. Review open requirements ($1.count tickets active)\n2. Prioritize backlog items\n3. Identify blockers and dependencies\n4. Assign ownership and action items\n\n**Open Tickets Summary:**\n$1.results\n\n📆 Calendar invites have been sent. Please confirm attendance."
      },
      "depends_on": [1, 4, 5]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "slack_agenda_posted",
        "resource_type": "slack_message",
        "resource_id": "$6.message_id",
        "details": {
          "channel": "#cross-team-collaboration",
          "related_event_id": "$4.event_id",
          "tickets_referenced": "$1.count"
        }
      },
      "depends_on": [6]
